import json
import requests


class Client:
    def __init__(self, base_url):
        self.base_url = base_url

    def send_event(self, payload):
        url = f'{self.base_url}/events'
        # BUG: requests.post(json=...) already serializes; double-encoding
        resp = requests.post(url, json=json.dumps(payload))
        return resp


def send_event(payload):
    c = Client('https://example.invalid')
    return c.send_event(payload)


def main():
    send_event({'user': 1, 'action': 'click'})


if __name__ == '__main__':
    main()
